-- ============================================================\n-- PRODUCT & SERVICE PLATFORM — Migration 11: Global Settings & Health Metrics\n-- ============================================================\n\n-- Global system settings\nCREATE TABLE IF NOT EXISTS public.system_settings (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  setting_key TEXT NOT NULL UNIQUE,\n  setting_value TEXT NOT NULL,\n  category TEXT NOT NULL DEFAULT 'General',\n  description TEXT,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),\n  updated_by UUID REFERENCES auth.users(id) ON DELETE SET NULL\n);\n\n-- Populate default configurations\nINSERT INTO public.system_settings (setting_key, setting_value, category, description)\nVALUES\n  ('default_tax_rate', '15.00', 'Tax', 'Standard value-added tax rate in percentage'),\n  ('base_currency', 'SAR', 'Localization', 'Default currency used across billing systems'),\n  ('ai_pricing_enabled', 'false', 'AI Engine', 'Toggle AI-driven market margin fluctuations'),\n  ('system_maintenance_mode', 'false', 'Security', 'Lock down non-admin interface actions')\nON CONFLICT (setting_key) DO UPDATE\nSET setting_value = EXCLUDED.setting_value,\n    category = EXCLUDED.category,\n    description = EXCLUDED.description;\n\n-- System health metrics tracking\nCREATE TABLE IF NOT EXISTS public.system_health_metrics (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  uptime_percentage NUMERIC(5,2) DEFAULT 100.00,\n  api_latency_ms INTEGER DEFAULT 45,\n  db_connections INTEGER DEFAULT 12,\n  recorded_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Insert mock initial health stats\nINSERT INTO public.system_health_metrics (uptime_percentage, api_latency_ms, db_connections)\nVALUES (99.98, 38, 14);\n\n-- System-wide admin audit log trail\nCREATE TABLE IF NOT EXISTS public.admin_audit_logs (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,\n  action_type TEXT NOT NULL,\n  details TEXT,\n  ip_address TEXT,\n  user_agent TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Enable RLS\nALTER TABLE public.system_settings ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.system_health_metrics ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.admin_audit_logs ENABLE ROW LEVEL SECURITY;\n\n-- RLS Policies\nCREATE POLICY \"System settings visible to authenticated\"\n  ON public.system_settings FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"Admins update system settings\"\n  ON public.system_settings FOR ALL TO authenticated USING (TRUE);\n\nCREATE POLICY \"Uptime and health visible to everyone\"\n  ON public.system_health_metrics FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"Audit trail visible to authenticated admins\"\n  ON public.admin_audit_logs FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"Audit insert allowed to system\"\n  ON public.admin_audit_logs FOR INSERT WITH CHECK (TRUE);\n
